from dataclasses import dataclass
from typing import List, Dict, Tuple
import math
import random

GPU_MEM_SIZE = 80  # GB

@dataclass
class Model:
    model_name: str
    model_size: int   # GB
    req_rate: int     # requests per second
    slo: int          # service level objective (latency target)
    cur_gpu_id: int   # current GPU assignment (can be ignored)

def compute_model_placement(gpu_num: int, models: list[Model]) -> dict[int, list[Model]]:
    '''
    Compute optimal model placement across GPUs to minimize max KVPR.

    Args:
        gpu_num: Number of available GPUs (typically 5-10)
        models: List of Model objects to place

    Returns:
        dict mapping gpu_id (int) to list of Models assigned to that GPU
        Example: {0: [model_a, model_b], 1: [model_c], 2: [model_d, model_e]}

    Constraints:
        - Each model must be assigned to exactly one GPU
        - Total model_size on each GPU must not exceed GPU_MEM_SIZE (80GB)

    Goal:
        Minimize max(KVPR) across all GPUs where:
        KVPR(gpu) = sum(req_rate/slo) / (GPU_MEM_SIZE - sum(model_size))
    '''

    # Hybrid approach: Binary Search + Simulated Annealing refinement
    # Use binary search on KVPR threshold to find a feasible baseline,
    # then refine with simulated annealing for better objective value

    n = len(models)
    if n == 0:
        return {i: [] for i in range(gpu_num)}

    # Precompute model metrics
    def get_model_weight(model: Model, T: float) -> float:
        return T * model.model_size + (model.req_rate / model.slo)

    def can_achieve_threshold(T: float) -> Tuple[bool, Dict[int, List[Model]]]:
        capacity = 80.0 * T
        models_with_weights = [(m, get_model_weight(m, T)) for m in models]
        models_with_weights.sort(key=lambda x: x[1], reverse=True)

        gpu_weights = [0.0] * gpu_num
        placement = {i: [] for i in range(gpu_num)}

        for model, weight in models_with_weights:
            placed = False
            for g in range(gpu_num):
                if gpu_weights[g] + weight <= capacity + 1e-9:
                    gpu_weights[g] += weight
                    placement[g].append(model)
                    placed = True
                    break
            if not placed:
                return False, {}

        # Final verification
        for g in range(gpu_num):
            if not placement[g]:
                continue
            total_load = sum(m.req_rate / m.slo for m in placement[g])
            total_size = sum(m.model_size for m in placement[g])
            actual_kvpr = total_load / (GPU_MEM_SIZE - total_size)
            if actual_kvpr > T + 1e-6:
                return False, {}

        return True, placement

    # Total memory check
    total_size = sum(m.model_size for m in models)
    if total_size > GPU_MEM_SIZE * gpu_num:
        # Fallback: Greedy by size
        sorted_models = sorted(models, key=lambda m: m.model_size, reverse=True)
        placement = {i: [] for i in range(gpu_num)}
        for m in sorted_models:
            best_gpu = max(range(gpu_num), key=lambda g: GPU_MEM_SIZE - sum(x.model_size for x in placement[g]))
            placement[best_gpu].append(m)
        return placement

    # Binary search setup
    total_load = sum(m.req_rate / m.slo for m in models)
    worst_size = max(total_size - GPU_MEM_SIZE * (gpu_num - 1), 0.1)
    upper_bound = total_load / worst_size * 1.5
    lower_bound = 0.0

    # Refine upper bound
    avg_load = total_load / gpu_num
    avg_size = total_size / gpu_num
    if avg_size < 80:
        rough_bound = avg_load / (80 - avg_size)
        upper_bound = min(upper_bound, rough_bound * 2.0)

    while not can_achieve_threshold(upper_bound)[0]:
        upper_bound *= 2.0

    # Binary search for feasible threshold
    best_placement = None
    for _ in range(60):
        mid = (lower_bound + upper_bound) / 2.0
        feasible, placement = can_achieve_threshold(mid)
        if feasible:
            best_placement = placement
            upper_bound = mid
        else:
            lower_bound = mid
        if upper_bound - lower_bound < 1e-9:
            break

    # Fallback to greedy if no feasible solution found
    if best_placement is None:
        sorted_models = sorted(models, key=lambda m: (m.req_rate / m.slo) / m.model_size, reverse=True)
        placement = {i: [] for i in range(gpu_num)}
        for m in sorted_models:
            best_gpu = -1
            min_score = float('inf')
            for g in range(gpu_num):
                current_size = sum(x.model_size for x in placement[g])
                if current_size + m.model_size > GPU_MEM_SIZE:
                    continue
                current_load = sum(x.req_rate / x.slo for x in placement[g])
                new_load = current_load + (m.req_rate / m.slo)
                new_size = current_size + m.model_size
                score = new_load / (GPU_MEM_SIZE - new_size)
                if score < min_score:
                    min_score = score
                    best_gpu = g
            if best_gpu != -1:
                placement[best_gpu].append(m)
            else:
                best_gpu = max(range(gpu_num), key=lambda g: GPU_MEM_SIZE - sum(x.model_size for x in placement[g]))
                placement[best_gpu].append(m)
        best_placement = placement

    # Refine with simulated annealing for better objective
    def compute_kvpr_for_gpu(gpu_models: List[Model]) -> float:
        if not gpu_models:
            return 0.0
        total_size = sum(m.model_size for m in gpu_models)
        if total_size >= GPU_MEM_SIZE:
            return float('inf')
        total_load = sum(m.req_rate / m.slo for m in gpu_models)
        return total_load / (GPU_MEM_SIZE - total_size)

    def calculate_objective(placement: Dict[int, List[Model]]) -> float:
        return max(compute_kvpr_for_gpu(gpu_models) for gpu_models in placement.values())

    current_placement = {k: v[:] for k, v in best_placement.items()}
    best_score = calculate_objective(current_placement)

    # Simulated annealing parameters
    temperature = 1.0
    cooling_rate = 0.995
    min_temperature = 0.001
    iterations_per_temp = 100
    max_iterations = 10000

    iteration = 0
    while temperature > min_temperature and iteration < max_iterations:
        for _ in range(iterations_per_temp):
            # Select source GPU (highest KVPR)
            source_gpu = max(range(gpu_num), key=lambda g: compute_kvpr_for_gpu(current_placement[g]))
            if not current_placement[source_gpu]:
                continue

            # Select destination GPU (lowest KVPR, not source)
            candidates = [g for g in range(gpu_num) if g != source_gpu]
            if not candidates:
                continue
            dest_gpu = min(candidates, key=lambda g: compute_kvpr_for_gpu(current_placement[g]))

            # Randomly select model from source
            model_idx = random.randint(0, len(current_placement[source_gpu]) - 1)
            model_to_move = current_placement[source_gpu][model_idx]

            # Check memory constraint
            dest_size = sum(m.model_size for m in current_placement[dest_gpu])
            if dest_size + model_to_move.model_size > GPU_MEM_SIZE:
                continue

            # Simulate move
            old_source_kvpr = compute_kvpr_for_gpu(current_placement[source_gpu])
            old_dest_kvpr = compute_kvpr_for_gpu(current_placement[dest_gpu])
            old_max = max(old_source_kvpr, old_dest_kvpr)
            for g in range(gpu_num):
                if g not in [source_gpu, dest_gpu]:
                    old_max = max(old_max, compute_kvpr_for_gpu(current_placement[g]))

            current_placement[source_gpu].pop(model_idx)
            current_placement[dest_gpu].append(model_to_move)

            new_source_kvpr = compute_kvpr_for_gpu(current_placement[source_gpu])
            new_dest_kvpr = compute_kvpr_for_gpu(current_placement[dest_gpu])
            new_max = max(new_source_kvpr, new_dest_kvpr)
            for g in range(gpu_num):
                if g not in [source_gpu, dest_gpu]:
                    new_max = max(new_max, compute_kvpr_for_gpu(current_placement[g]))

            # Acceptance
            delta = new_max - old_max
            accept = delta < 0 or (random.random() < math.exp(-delta / temperature))

            if accept:
                if new_max < best_score:
                    best_score = new_max
                    best_placement = {k: v[:] for k, v in current_placement.items()}
            else:
                # Undo
                current_placement[dest_gpu].pop()
                current_placement[source_gpu].insert(model_idx, model_to_move)

            iteration += 1

        temperature *= cooling_rate

    return best_placement

